/**
 * Localized message catalog — everything the AGENT says that is not generated by the LLM.
 *
 * WHY these strings are data and not prompt output: they are said at moments where we
 * cannot afford a model round-trip (fillers, no-input reprompts) or where the wording is
 * legally load-bearing (the AI disclosure, docs/14 / EU AI Act). Both cases need a string
 * that is fixed, reviewed, and translated by a human — not paraphrased per call.
 *
 * REGISTER IS ENFORCED BY THE TYPE SYSTEM. For any locale whose `tv` field in locales.ts
 * is non-null, every catalog entry must supply BOTH a `formal` and an `informal` variant.
 * Omitting one is a compile error, not a runtime surprise where a German customer hears
 * "du" from a bank's agent. docs/13 §4: getting this wrong is offensive in a way English
 * has no equivalent for.
 *
 * TRANSLATION RULES followed here:
 *   - Idiomatic, not translated-from-English. German says "Einen Moment, ich schaue nach.",
 *     never a literal rendering of "let me check that for you".
 *   - Register is consistent within a string AND within a locale.
 *   - Where a language's polite form is gendered (pl Pan/Pani, pt-BR o senhor/a senhora)
 *     the formal variant uses an impersonal construction instead, because we do not know
 *     the caller's gender and guessing it is worse than avoiding it.
 *   - Regional variants differ only where it genuinely matters (es-MX preterite vs es-ES
 *     present perfect, pt-PT "estar a fazer" vs pt-BR gerund, fr-CA/fr-BE idiom).
 *
 * Locales we are not confident in are marked `beta` in locales.ts and are therefore absent
 * from `CatalogLocale`; they resolve through the Localizer's logged fallback chain instead.
 */

import type { CatalogLocale, TvLocale } from './locales.js';

/** Both registers, required together. */
export interface ByRegister<T> {
  readonly formal: T;
  readonly informal: T;
}

/** T-V locales get a register pair; everything else gets the bare value. */
export type Registered<L extends CatalogLocale, T> = L extends TvLocale ? ByRegister<T> : T;

/** A complete translation set. Missing locale OR missing register => compile error. */
export type Catalog<T> = { readonly [L in CatalogLocale]: Registered<L, T> };

/** Escalating no-input ladder: nudge, explicit instruction, graceful exit. docs/03 2.11. */
export type RepromptLadder = readonly [string, string, string];
export type RepromptLevel = 1 | 2 | 3;

export type ErrorKind = 'line_quality' | 'no_understand' | 'wrapping_up';
export type ErrorMessages = { readonly [K in ErrorKind]: string };

/** Substituted with the recognised value by `Localizer.confirm()`. */
export const CONFIRM_PLACEHOLDER = '{value}';

// ---------------------------------------------------------------------------
// AI disclosure — EU AI Act transparency obligation (docs/14, docs/13 §2)
//
// Always spoken in the FORMAL register regardless of the agent's configured register:
// this is a legal statement, and the informal variants exist only because the type
// demands symmetry (and because an agent that is informal throughout would sound
// bizarre switching to Sie for one sentence in a low-stakes consumer flow).
// `Localizer.disclosure()` ignores the register preference and always returns formal.
// ---------------------------------------------------------------------------

