/** Everything, grouped by purpose. The Localizer is the only intended consumer. */
export const MESSAGES = {
  aiDisclosure,
  fillers,
  reprompts,
  handoff,
  confirmations,
  errors,
} as const;

export type MessageGroup = keyof typeof MESSAGES;

/** Runtime narrowing for the `Registered<L, T>` union — the shape tells us the locale kind. */
export function isByRegister<T>(entry: ByRegister<T> | T): entry is ByRegister<T> {
  return (
    typeof entry === 'object' &&
    entry !== null &&
    !Array.isArray(entry) &&
    'formal' in entry &&
    'informal' in entry
  );
}

/** Collapse a catalog entry to a single value for the requested register. */
export function pickRegister<T>(entry: ByRegister<T> | T, register: 'formal' | 'informal'): T {
  return isByRegister<T>(entry) ? entry[register] : entry;
}
